Body:
Resgate de Pontos

body {
font-family: Arial, sans-serif;
text-align: center;
}

.banner {
max-width: 600px;
margin: 0 auto;
padding: 20px;
background-color: #ffffff;
border-bottom: 2px solid red;
}

.banner img {
max-width: 100%;
}

.banner h1 {
color: #b41010;
font-size: 24px;
margin-bottom: 10px;
font-weight: bold;
}

.banner p {
color: #444444;
font-size: 18px;
font-weight: bold;
}

.button {
display: inline-block;
padding: 10px 20px;
background-color: #b41010;
color: #ffffff;
font-size: 16px;
font-weight: bold;
text-decoration: none;
border-radius: 5px;
border: none;
transition: all 0.3s ease;
cursor: pointer;
}

.button:hover {
transform: translateY(-3px);
box-shadow: 0px 5px 10px rgba(0, 0, 0, 0.2);
}

.advantages {
max-width: 600px;
margin: 20px auto;
background-color: #ffffff;
padding: 20px;
color: #444444;
text-align: center;
font-weight: bold;
}

.advantages h2 {
color: #b41010;
font-size: 20px;
margin-bottom: 10px;
font-weight: bold;
}

.advantages ul {
list-style-type: disc;
margin-left: 20px;
text-align: left;
}

.advantages li {
margin-bottom: 5px;
font-weight: bold;
}

.footer {
padding: 20px;
color: #444444;
text-align: center;
font-weight: bold;
}

